    let gap = reward1.map((value, index) => ({ diff: reward2[index] - value, index })).sort((a, b) => b.diff - a.diff);
    let firstMousePoints = 0;
    let secondMousePoints = 0;
    for (let i = 0; i < k; ++i) {
        firstMousePoints += reward1[gap[i].index];
    }
    for (let i = k; i < reward1.length; ++i) {
        secondMousePoints += reward2[gap[i].index];
    }
    return firstMousePoints + secondMousePoints;
}
