import java.util.ArrayList;
import java.util.Collections;
import java.util.Comparator;
import java.util.List;

public int maxPoints(int[] reward1, int[] reward2, int k) {
    List<Pair<Integer, Integer>> gap = new ArrayList<>();
    for (int i = 0; i < reward1.length; ++i) {
        gap.add(new Pair<>(reward2[i] - reward1[i], i));
    }
    Collections.sort(gap, Comparator.reverseOrder());
    int firstMousePoints = 0;
    int secondMousePoints = 0;
    for (int i = 0; i < k; ++i) {
        firstMousePoints += reward1[gap.get(i).getValue()];
    }
    for (int i = k; i < reward1.length; ++i) {
        secondMousePoints += reward2[gap.get(i).getValue()];
    }
    return firstMousePoints + secondMousePoints;
}
```

